{
  "executive_summary": "Architecture for a real-time ML delivery time estimation service with a decoupled training pipeline, model versioning for instant rollback, and a lightweight online inference path optimized for sub-100ms P99 latency at checkout. The design separates the hot path (inference) from the cold path (training/evaluation) to let a 4-person team operate independently on model quality vs serving reliability.",

  "architecture": {
    "components": [
      {
        "name": "Inference Service",
        "responsibility": "Serves predictions via a stateless HTTP/gRPC endpoint. Loads the active model version into memory at startup and on promotion signals. Pre-computes feature transformations. Returns predicted delivery time in minutes.",
        "boundaries": "Owns ONLY prediction serving. No training logic, no raw data access. Reads from Feature Store (cache layer) and Model Registry. Horizontally scalable behind a load balancer."
      },
      {
        "name": "Feature Store (Online)",
        "responsibility": "Serves pre-computed and real-time features with sub-10ms latency. Caches zone-level aggregates (avg courier load, weather conditions) in Redis. Computes point-in-time features for each request (distance, weight, time-of-day are passed through; courier load and weather are looked up).",
        "boundaries": "Read-only from Inference Service perspective. Written to by the Feature Pipeline. Backed by Redis with TTLs aligned to feature freshness requirements."
      },
      {
        "name": "Feature Pipeline",
        "responsibility": "Batch and streaming ETL that materializes features into the Online Feature Store and Offline Feature Store. Streaming path updates courier load and weather every 1-5 minutes. Batch path computes historical training features nightly.",
        "boundaries": "Owns feature computation logic — single source of truth for feature definitions. Consumes from Order Events, Weather API, and Courier Tracking streams."
      },
      {
        "name": "Training Pipeline",
        "responsibility": "Weekly automated pipeline: pulls historical features + delivery outcomes from the Offline Feature Store, trains the model (gradient-boosted trees — LightGBM/XGBoost), evaluates against holdout set and shadow traffic baseline, publishes a candidate model to the Model Registry.",
        "boundaries": "Runs on a schedule (weekly cron or Airflow DAG). No direct access to production inference. Outputs a versioned model artifact. ML engineers own this entirely."
      },
      {
        "name": "Model Registry",
        "responsibility": "Stores versioned model artifacts with metadata (training date, evaluation metrics, dataset hash, promotion status). Supports states: candidate → active → retired. Exactly one model is 'active' at any time.",
        "boundaries": "Source of truth for which model version is live. Inference Service polls or subscribes to promotion events. Platform engineers control promotion; ML engineers control training."
      },
      {
        "name": "Model Evaluator / Shadow Scorer",
        "responsibility": "Runs the candidate model against live traffic in shadow mode (does not affect responses). Compares candidate vs active model on MAE, P50/P95 error, and bias metrics. Generates a promotion report. Optionally gates auto-promotion if metrics meet thresholds.",
        "boundaries": "Read-only on live traffic. Writes evaluation results to the Model Registry. Does not serve customer-facing predictions."
      },
      {
        "name": "Delivery Outcome Collector",
        "responsibility": "Captures actual delivery times from courier tracking events and joins them with the original prediction request (by order ID). Writes labeled examples to the Offline Feature Store for future training.",
        "boundaries": "Asynchronous. Eventual consistency is fine — training data can lag by hours. Owns the feedback loop closure."
      },
      {
        "name": "API Gateway / Checkout Service Integration",
        "responsibility": "Existing checkout service calls the Inference Service synchronously. A circuit breaker with a fallback (zone-based lookup table) protects checkout if inference is unavailable.",
        "boundaries": "Owned by the platform team. The fallback is a simple static lookup — no ML involved — ensuring checkout never blocks on prediction failures."
      }
    ],
    "interfaces": [
      {
        "from": "Checkout Service",
        "to": "Inference Service",
        "contract": "POST /predict { weight, distance, zone, time_of_day } → { estimated_minutes, confidence_interval, model_version } — P99 < 100ms",
        "coupling_type": "synchronous, runtime"
      },
      {
        "from": "Inference Service",
        "to": "Feature Store (Online)",
        "contract": "GET features by (zone, time_window) → { weather_code, avg_courier_load, zone_congestion_score } — P99 < 10ms (Redis)",
        "coupling_type": "synchronous, runtime"
      },
      {
        "from": "Inference Service",
        "to": "Model Registry",
        "contract": "Subscribe to model-promoted events OR poll /models/active → { artifact_url, version } — checked every 30s or on event",
        "coupling_type": "asynchronous, deployment-time"
      },
      {
        "from": "Training Pipeline",
        "to": "Model Registry",
        "contract": "PUT /models/{version} { artifact, metrics, dataset_hash } — publishes candidate",
        "coupling_type": "asynchronous, batch"
      },
      {
        "from": "Feature Pipeline",
        "to": "Feature Store (Online)",
        "contract": "WRITE features keyed by (zone, time_window) — streaming updates every 1-5 min",
        "coupling_type": "asynchronous, streaming"
      },
      {
        "from": "Model Evaluator",
        "to": "Model Registry",
        "contract": "PATCH /models/{version}/evaluation { shadow_metrics, recommendation } — updates candidate status",
        "coupling_type": "asynchronous, batch"
      },
      {
        "from": "Delivery Outcome Collector",
        "to": "Offline Feature Store",
        "contract": "WRITE (order_id, predicted_minutes, actual_minutes, features_snapshot) — append-only labeled examples",
        "coupling_type": "asynchronous, event-driven"
      }
    ],
    "data_flow": "1) Checkout request arrives with order details → 2) Inference Service enriches with real-time features from Redis (weather, courier load) → 3) Model predicts delivery time using in-memory LightGBM model → 4) Response returned in <100ms. TRAINING LOOP: A) Delivery outcomes flow into Outcome Collector → B) Joined with prediction features into Offline Store → C) Weekly Training Pipeline pulls labeled data, trains new model → D) Candidate published to Registry → E) Shadow Evaluator scores candidate against live traffic → F) Platform engineer promotes or rolls back via Registry state change → G) Inference Service hot-reloads new model.",
    "patterns_used": [
      {
        "pattern": "Two-Phase Model Serving (Shadow + Promote)",
        "rationale": "Decouples model training from serving. New models run in shadow mode before promotion, giving a safe rollback point. Rollback is instant — flip the active pointer in the Registry."
      },
      {
        "pattern": "Online/Offline Feature Store Split",
        "rationale": "Online store (Redis) for sub-10ms feature lookups on the hot path. Offline store (S3/Parquet or data warehouse) for training. Prevents training concerns from affecting serving latency."
      },
      {
        "pattern": "Circuit Breaker with Static Fallback",
        "rationale": "Checkout is a critical path. If the Inference Service is degraded, fall back to a zone-based average lookup table. Customers get a rougher estimate, but checkout never blocks."
      },
      {
        "pattern": "Immutable Model Versioning",
        "rationale": "Every trained model is an immutable, versioned artifact. Rollback is a pointer swap, not a retrain. Audit trail of every model that has served production traffic."
      },
      {
        "pattern": "In-Process Model Inference (no inter-service call)",
        "rationale": "LightGBM/XGBoost models are loaded directly into the inference service process memory. A single prediction takes <1ms of compute, leaving ample budget for network + feature fetch within the 100ms P99 target. No need for a separate model serving framework (TF Serving, Triton) for tree-based models."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Prediction Serving",
        "classification": "core",
        "aggregates": ["PredictionRequest (value object: weight, distance, zone, time_of_day, enriched features → predicted_minutes, model_version)"]
      },
      {
        "name": "Model Lifecycle",
        "classification": "core",
        "aggregates": ["ModelVersion (entity: version_id, artifact_url, state [candidate|active|retired], training_metrics, shadow_metrics, promoted_at, promoted_by)"]
      },
      {
        "name": "Feature Engineering",
        "classification": "supporting",
        "aggregates": ["FeatureSet (value object: zone features, temporal features, weather features — versioned by feature schema)"]
      },
      {
        "name": "Training & Evaluation",
        "classification": "supporting",
        "aggregates": ["TrainingRun (entity: run_id, dataset_hash, hyperparams, metrics, model_version_produced)", "EvaluationReport (entity: candidate_version, baseline_version, comparison_metrics, recommendation)"]
      },
      {
        "name": "Delivery Feedback",
        "classification": "supporting",
        "aggregates": ["DeliveryOutcome (entity: order_id, predicted_minutes, actual_minutes, features_at_prediction_time)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Model Lifecycle",
        "downstream": "Prediction Serving",
        "relationship": "Customer-Supplier — Model Lifecycle publishes active model artifacts; Prediction Serving consumes them. Serving team can request model format constraints."
      },
      {
        "upstream": "Feature Engineering",
        "downstream": "Prediction Serving",
        "relationship": "Shared Kernel — Feature definitions must be identical between training and serving to avoid training-serving skew. Shared feature schema is the kernel."
      },
      {
        "upstream": "Feature Engineering",
        "downstream": "Training & Evaluation",
        "relationship": "Customer-Supplier — Training consumes offline features materialized by Feature Engineering."
      },
      {
        "upstream": "Delivery Feedback",
        "downstream": "Training & Evaluation",
        "relationship": "Conformist — Training conforms to whatever label schema Delivery Feedback produces."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "LightGBM/XGBoost (tree-based) over deep learning",
      "gains": "Sub-millisecond inference in-process, interpretable feature importances, works well with tabular data and small-medium feature sets, simple to deploy (single binary/shared lib), tiny model artifact size",
      "sacrifices": "May underperform deep learning if there are complex non-linear interactions that trees miss; harder to incorporate unstructured inputs (e.g., delivery notes text) later",
      "alternatives_considered": ["Neural network (PyTorch/TF) — higher latency, needs GPU or model serving infra, overkill for 6-feature tabular regression", "Linear regression — too simple, can't capture zone × time-of-day interactions", "Ensemble of trees + neural — complexity not warranted for a 4-person team"]
    },
    {
      "decision": "Redis for online feature store over a managed feature platform (Feast, Tecton)",
      "gains": "Simple, fast, well-understood by platform engineers, no vendor lock-in, sub-10ms lookups guaranteed",
      "sacrifices": "No built-in feature versioning or lineage tracking — must build feature schema management manually. No point-in-time join semantics for online features (handled in offline store for training).",
      "alternatives_considered": ["Feast — good OSS option but adds operational overhead for a 4-person team", "Tecton — excellent but expensive SaaS, overkill at this scale", "DynamoDB — viable but Redis is faster for this access pattern"]
    },
    {
      "decision": "Weekly batch retraining over online/continuous learning",
      "gains": "Simple, auditable, easy to debug. Full control over training data quality. Aligns with team size — no need for real-time ML ops.",
      "sacrifices": "Model can be stale for up to 7 days if delivery patterns shift (e.g., holiday surge). Mitigated by the ability to trigger ad-hoc retraining.",
      "alternatives_considered": ["Daily retraining — more freshness but 7x compute cost and operational burden", "Online learning — too complex for 4 people, hard to debug, model drift risks"]
    },
    {
      "decision": "Shadow scoring before promotion over A/B testing",
      "gains": "Zero customer impact from bad models — shadow mode sees real traffic but doesn't affect responses. Simpler than A/B infrastructure. Safe rollback by never promoting.",
      "sacrifices": "Can't measure actual user behavior impact (e.g., does more accurate ETA increase conversion?). Mitigated: can layer A/B testing later once the platform matures.",
      "alternatives_considered": ["A/B testing — richer signal but requires traffic splitting infrastructure, more complex for 4 people", "Canary deployment — viable but shadow is even safer since it has zero customer exposure"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Model algorithm",
      "evolution_path": "The Inference Service loads any model that conforms to the predict(features) → float interface. Can swap LightGBM for XGBoost, a neural net, or an ensemble without changing serving code. Model Registry is algorithm-agnostic."
    },
    {
      "area": "Feature set",
      "evolution_path": "Adding new features requires: 1) add to Feature Pipeline, 2) add to feature schema (shared kernel), 3) retrain. No inference service code change needed — features are a dynamic vector."
    },
    {
      "area": "Retraining frequency",
      "evolution_path": "Cron schedule is a config knob. Can go from weekly → daily → triggered-on-drift with no architectural change. Just adjust the scheduler."
    },
    {
      "area": "Fallback strategy",
      "evolution_path": "Static lookup table can evolve to a simpler statistical model, or a cached recent prediction. The circuit breaker pattern allows swapping fallback implementations."
    }
  ],

  "rigidity_points": [
    {
      "area": "Feature parity between training and serving (training-serving skew)",
      "reason": "This is intentionally rigid. The same feature definitions MUST be used in both offline training and online serving. This is the single most common source of ML system bugs. Enforced via the shared feature schema (Shared Kernel). Breaking this parity must be treated as a breaking change."
    },
    {
      "area": "Model artifact format",
      "reason": "Models must be serializable to a format loadable in-process (e.g., LightGBM binary, ONNX). Moving to a model that requires a GPU serving runtime would be an architectural change, not just a model swap."
    },
    {
      "area": "Synchronous inference on checkout path",
      "reason": "The 100ms P99 contract is non-negotiable. Any change that adds network hops or external service calls to the prediction hot path must be scrutinized against this budget."
    }
  ],

  "risks": [
    {
      "risk": "Training-serving skew: features computed differently in batch (training) vs real-time (serving), causing silent model degradation",
      "severity": "critical",
      "mitigation": "Shared feature schema as code (the Shared Kernel). Integration tests that compute features both ways on the same input and assert equality. Log feature vectors at serving time and compare against training distribution (feature drift monitoring)."
    },
    {
      "risk": "Stale features in Redis causing inaccurate predictions (e.g., weather data not updated, courier load from hours ago)",
      "severity": "high",
      "mitigation": "TTLs on all Redis keys (e.g., weather: 15min, courier load: 5min). If a feature is missing/expired, use a safe default and log a warning. Monitor feature freshness as a system health metric."
    },
    {
      "risk": "Model degradation goes undetected after promotion",
      "severity": "high",
      "mitigation": "Continuous monitoring of prediction error (predicted vs actual, once delivery completes). Alert on MAE increase >15% over a rolling 24h window. Automated rollback trigger if error exceeds threshold."
    },
    {
      "risk": "Redis failure takes down predictions on the checkout hot path",
      "severity": "high",
      "mitigation": "Circuit breaker falls back to static zone lookup table. Redis deployed as a cluster with replicas. Inference service can also cache the last-known feature values locally with a short TTL as a second-tier fallback."
    },
    {
      "risk": "4-person team stretched thin across ML and platform concerns",
      "severity": "medium",
      "mitigation": "Clear ownership split: 2 ML engineers own Training Pipeline + Feature Pipeline + Model Evaluator. 2 Platform engineers own Inference Service + Model Registry + Feature Store infra + monitoring. Minimize custom tooling — use managed services where possible (e.g., S3 for model artifacts, Airflow/managed orchestrator for training schedule)."
    },
    {
      "risk": "Feedback loop delay: actual delivery times arrive hours after prediction, slowing iteration",
      "severity": "low",
      "mitigation": "Acceptable for weekly retraining cadence. If moving to faster retraining, would need to prioritize reducing this delay. Current design handles it fine."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (Weeks 1-3): Stand up the Inference Service with a hand-tuned heuristic model (zone-distance lookup) behind the /predict API. Integrate with checkout. This gets the interface contract live immediately. Phase 2 (Weeks 3-5): Build the Feature Pipeline and Online Feature Store (Redis). Train the first LightGBM model offline, manually publish to Model Registry (can be S3 + a JSON metadata file initially). Swap heuristic for ML model. Phase 3 (Weeks 5-7): Automate the Training Pipeline (Airflow DAG or simple cron). Build the Delivery Outcome Collector to close the feedback loop. Phase 4 (Weeks 7-9): Build Shadow Evaluator. Add monitoring dashboards (prediction error, feature freshness, latency). Implement automated rollback triggers. Ship the circuit breaker fallback.",
    "files_to_create_or_modify": [
      "services/inference/main.py — FastAPI/gRPC service, model loading, /predict endpoint",
      "services/inference/model_loader.py — polls Model Registry, hot-reloads model on promotion",
      "services/inference/feature_client.py — Redis feature lookup with fallback",
      "services/inference/fallback.py — static zone-based lookup table for circuit breaker",
      "pipelines/feature_pipeline/ — streaming + batch feature computation (shared feature definitions)",
      "pipelines/training_pipeline/ — Airflow DAG or script: data pull → train → evaluate → publish",
      "pipelines/outcome_collector/ — event consumer joining predictions with actual delivery times",
      "model_registry/ — S3 bucket structure + metadata store (DynamoDB or Postgres table)",
      "shared/feature_schema.py — THE shared kernel: feature names, types, defaults, version",
      "monitoring/dashboards/ — Grafana dashboards for latency, prediction error, feature freshness",
      "tests/integration/test_feature_parity.py — asserts offline and online features produce identical results"
    ],
    "patterns_to_follow": "Use the shared feature_schema.py as the single source of truth for feature definitions — both the training pipeline and inference service import from it. Model artifacts stored as immutable versioned objects in S3 (path: s3://models/{model_name}/v{version}/model.lgb). Redis keys follow the pattern: features:{zone}:{time_window}. All prediction requests log: (request_id, order_id, features, prediction, model_version) for debugging and outcome joining.",
    "pitfalls_to_avoid": [
      "DO NOT compute features differently in training vs serving — this is the #1 ML systems failure mode. Use the shared feature schema.",
      "DO NOT add network hops to the prediction hot path — keep model in-process, features in Redis on the same VPC.",
      "DO NOT skip the shadow evaluation phase — promoting untested models to production will cause customer-facing regressions.",
      "DO NOT use a heavyweight model serving framework (TF Serving, Triton, SageMaker endpoints) for tree-based models — it adds latency, complexity, and cost for no benefit.",
      "DO NOT store model artifacts in the database — use S3/GCS for blobs, database for metadata only.",
      "DO NOT make the rollback process require a redeployment — it must be a metadata state change that the inference service picks up within seconds."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Inference architecture: in-process tree model + Redis features is well-proven for sub-100ms tabular prediction",
      "Model versioning and rollback: immutable artifacts with pointer-swap promotion is standard practice",
      "Team split: 2 ML + 2 platform maps cleanly to training pipeline vs serving infrastructure ownership",
      "Training-serving skew mitigation via shared feature schema"
    ],
    "low_confidence_areas": [
      "Exact feature freshness requirements for weather and courier load — depends on how volatile these are in practice; may need tuning",
      "Whether weekly retraining is sufficient — depends on delivery pattern seasonality; may need to go daily during peak periods",
      "Exact latency budget breakdown (feature fetch vs model inference vs network) — needs load testing to validate"
    ],
    "assumptions": [
      "Feature count stays in the low tens (6-20) — tree-based models are ideal here; if features grow to hundreds+, architecture still holds but model choice may change",
      "Traffic volume is moderate (hundreds to low thousands of QPS) — a few inference service replicas behind a load balancer suffice; if 10K+ QPS, would need to consider model caching and connection pooling more carefully",
      "The logistics platform already has an event stream for delivery tracking (courier GPS/status updates) — the Outcome Collector depends on this existing",
      "Infrastructure includes or can easily adopt Redis, S3, and a workflow orchestrator (Airflow or equivalent)"
    ]
  }
}

